// src/components/ProductCustomizationModal.js
import React, { useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiX, FiSend, FiCheck, FiLoader } from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import toast from 'react-hot-toast';

/* ─── Config ──────────────────────────────────────────────────────── */
const COLORS = [
  { name: 'Natural Brown', hex: '#8B4513' },
  { name: 'Ivory White', hex: '#FFFFF0', dark: true },
  { name: 'Midnight Black', hex: '#1a1a1a' },
  { name: 'Ruby Red', hex: '#9B2335' },
  { name: 'Ocean Blue', hex: '#1E6B8C' },
  { name: 'Forest Green', hex: '#2D6A4F' },
  { name: 'Golden Yellow', hex: '#D4AF37' },
  { name: 'Rose Pink', hex: '#E8A0BF', dark: true },
  { name: 'Deep Purple', hex: '#6B3FA0' },
  { name: 'Terracotta', hex: '#CB6D51' },
  { name: 'Teal', hex: '#008080' },
  { name: 'Cream', hex: '#FFFDD0', dark: true },
];

const SIZES = ['XS', 'S', 'M', 'L', 'XL', 'XXL', 'Custom'];

/* ─── Step indicator ──────────────────────────────────────────────── */
const StepDot = ({ n, active, done }) => (
  <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all ${done ? 'bg-violet-600 text-white' :
    active ? 'bg-violet-100 text-violet-700 ring-2 ring-violet-400' :
      'bg-gray-100 text-gray-400'
    }`}>
    {done ? <FiCheck className="h-3.5 w-3.5" /> : n}
  </div>
);

const ProductCustomizationModal = ({ product, onClose }) => {
  const { user } = useAuth();

  // Effective role: respects buyer-mode switching
  const canSendRequest = !!user; // Any logged in user
  const isOwnProduct = user && (
    String(user.id || user._id) === String(product.artisan?._id || product.artisan)
  );

  const [color, setColor] = useState(null);
  const [size, setSize] = useState('');
  const [notes, setNotes] = useState('');
  const [step, setStep] = useState(1);   // 1=colour  2=size  3=notes+review
  const [status, setStatus] = useState('idle'); // idle | sending | sent

  const hasColor = Boolean(color);
  const hasSize = Boolean(size);
  const hasNotes = notes.trim().length > 0;
  const hasAny = hasColor || hasSize || hasNotes;

  /* ─── Submit ──────────────────────────────────────────────────── */
  const handleSend = useCallback(async () => {
    if (!user) { toast.error('Please login to send customisation requests'); return; }
    if (isOwnProduct) { toast.error("You can't customise your own product", { icon: '🚫' }); onClose(); return; }
    if (!hasAny) { toast.error('Pick at least one option — colour, size, or notes'); return; }
    setStatus('sending');

    try {
      // Notify artisan via product endpoint → emits socket 'customization-request' popup
      await api.post(`/products/${product._id}/customization-request`, {
        color: color?.name || '',
        size,
        notes: notes.trim(),
      });

      setStatus('sent');
      toast.success('Request sent! Artisan has been notified.');

      setTimeout(() => {
        onClose();
      }, 1000);

    } catch (error) {
      setStatus('idle');
      toast.error('Failed to send. Try again.');
    }
  }, [hasAny, color, size, notes, product, onClose]);

  const imgSrc = product.images?.[0]?.url;
  const artisanName = product.artisan?.name || 'the artisan';

  return (
    <AnimatePresence>
      {/* Backdrop */}
      <motion.div
        key="backdrop"
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[9999] flex items-end sm:items-center justify-center p-0 sm:p-4"
        onClick={e => e.target === e.currentTarget && onClose()}
      >
        {/* Panel */}
        <motion.div
          key="panel"
          initial={{ y: 60, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 60, opacity: 0 }}
          transition={{ type: 'spring', damping: 28, stiffness: 320 }}
          className="bg-white w-full sm:max-w-md rounded-t-3xl sm:rounded-3xl shadow-2xl overflow-hidden flex flex-col"
          style={{ maxHeight: '92vh' }}
        >

          {/* ── Header ───────────────────────────────────────────── */}
          <div className="bg-gradient-to-r from-violet-600 to-purple-600 px-6 py-5 flex-shrink-0">
            <div className="flex items-start justify-between">
              <div className="flex-1 min-w-0">
                <h2 className="text-white font-bold text-lg leading-tight">Customise Product</h2>
                <p className="text-violet-200 text-xs mt-0.5 truncate">{product.name}</p>
              </div>
              <button onClick={onClose}
                className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 flex items-center justify-center ml-3 flex-shrink-0 transition-colors">
                <FiX className="h-4 w-4 text-white" />
              </button>
            </div>

            {/* Product preview strip */}
            <div className="flex items-center gap-3 mt-4 bg-white/15 rounded-2xl p-3">
              <div className="relative w-14 h-14 rounded-xl overflow-hidden flex-shrink-0 shadow-md">
                {imgSrc
                  ? <img src={imgSrc} alt={product.name} className="w-full h-full object-cover" />
                  : <div className="w-full h-full bg-white/20 flex items-center justify-center text-2xl">🎨</div>
                }
                {/* Live colour overlay */}
                <AnimatePresence>
                  {color && (
                    <motion.div
                      key={color.hex}
                      initial={{ opacity: 0 }} animate={{ opacity: 0.45 }} exit={{ opacity: 0 }}
                      className="absolute inset-0 mix-blend-multiply"
                      style={{ backgroundColor: color.hex }}
                    />
                  )}
                </AnimatePresence>
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-white font-semibold text-sm truncate">{product.name}</p>
                <p className="text-violet-200 text-xs capitalize">{product.category}</p>
                {/* Live selection preview */}
                <div className="flex gap-1.5 mt-1.5 flex-wrap">
                  {color && (
                    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-semibold bg-white/90"
                      style={{ color: color.dark ? '#374151' : color.hex }}>
                      <span className="w-2 h-2 rounded-full" style={{ background: color.hex }} />
                      {color.name}
                    </span>
                  )}
                  {size && (
                    <span className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-semibold bg-white/90 text-violet-700">
                      {size}
                    </span>
                  )}
                </div>
              </div>
            </div>

            {/* Step indicators */}
            <div className="flex items-center gap-2 mt-4">
              {[1, 2, 3].map(n => (
                <React.Fragment key={n}>
                  <StepDot n={n} active={step === n} done={step > n} />
                  {n < 3 && <div className={`flex-1 h-0.5 rounded-full transition-colors ${step > n ? 'bg-violet-400' : 'bg-white/20'}`} />}
                </React.Fragment>
              ))}
              <span className="text-violet-200 text-xs ml-2">
                {step === 1 ? 'Colour' : step === 2 ? 'Size' : 'Review'}
              </span>
            </div>
          </div>

          {/* ── Body ─────────────────────────────────────────────── */}
          <div className="flex-1 overflow-y-auto">
            <AnimatePresence mode="wait">

              {/* Step 1 — Colour ─────────────────────────────────── */}
              {step === 1 && (
                <motion.div key="step1"
                  initial={{ x: 40, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -40, opacity: 0 }}
                  transition={{ duration: 0.2 }}
                  className="p-6"
                >
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-gray-900">Choose a Colour</h3>
                    {color && (
                      <button onClick={() => setColor(null)} className="text-xs text-gray-400 hover:text-red-500 transition-colors">
                        Clear
                      </button>
                    )}
                  </div>
                  <div className="grid grid-cols-6 gap-3">
                    {COLORS.map(c => (
                      <motion.button
                        key={c.name}
                        whileTap={{ scale: 0.85 }}
                        whileHover={{ scale: 1.12 }}
                        onClick={() => setColor(prev => prev?.name === c.name ? null : c)}
                        title={c.name}
                        className={`relative w-11 h-11 rounded-full border-3 shadow-sm transition-all ${color?.name === c.name
                          ? 'border-violet-500 ring-4 ring-violet-200 scale-110'
                          : 'border-gray-200 hover:border-violet-300'
                          }`}
                        style={{ backgroundColor: c.hex, borderWidth: color?.name === c.name ? 3 : 2 }}
                      >
                        {color?.name === c.name && (
                          <FiCheck className="absolute inset-0 m-auto h-4 w-4 drop-shadow"
                            style={{ color: c.dark ? '#4b5563' : '#fff' }} />
                        )}
                      </motion.button>
                    ))}
                  </div>
                  {color && (
                    <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                      className="text-sm text-violet-700 font-medium mt-3 flex items-center gap-2">
                      <span className="w-3 h-3 rounded-full" style={{ backgroundColor: color.hex }} />
                      {color.name} selected
                    </motion.p>
                  )}
                </motion.div>
              )}

              {/* Step 2 — Size ───────────────────────────────────── */}
              {step === 2 && (
                <motion.div key="step2"
                  initial={{ x: 40, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -40, opacity: 0 }}
                  transition={{ duration: 0.2 }}
                  className="p-6"
                >
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-gray-900">Choose a Size</h3>
                    {size && (
                      <button onClick={() => setSize('')} className="text-xs text-gray-400 hover:text-red-500 transition-colors">
                        Clear
                      </button>
                    )}
                  </div>
                  <div className="grid grid-cols-4 gap-3">
                    {SIZES.map(s => (
                      <motion.button
                        key={s}
                        whileTap={{ scale: 0.92 }}
                        onClick={() => setSize(prev => prev === s ? '' : s)}
                        className={`py-3 rounded-xl border-2 font-semibold text-sm transition-all ${size === s
                          ? 'border-violet-500 bg-violet-500 text-white shadow-md scale-105'
                          : 'border-gray-200 text-gray-700 hover:border-violet-300 hover:bg-violet-50 hover:text-violet-700'
                          }`}
                      >
                        {s}
                      </motion.button>
                    ))}
                  </div>
                  {size && (
                    <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                      className="text-sm text-violet-700 font-medium mt-3">
                      Size <span className="font-bold">{size}</span> selected
                    </motion.p>
                  )}

                  {/* Size guide hint */}
                  <p className="text-xs text-gray-400 mt-4 leading-relaxed">
                    Not sure about size? Select <strong>Custom</strong> and describe your dimensions in the notes.
                  </p>
                </motion.div>
              )}

              {/* Step 3 — Notes + Review ────────────────────────── */}
              {step === 3 && (
                <motion.div key="step3"
                  initial={{ x: 40, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -40, opacity: 0 }}
                  transition={{ duration: 0.2 }}
                  className="p-6 space-y-5"
                >
                  {/* Review summary */}
                  <div className="bg-violet-50 rounded-2xl p-4 border border-violet-100">
                    <p className="text-xs font-bold text-violet-700 uppercase tracking-wider mb-3">Your Request</p>
                    <div className="space-y-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-gray-500">Product</span>
                        <span className="font-semibold text-gray-800 text-right max-w-[60%] truncate">{product.name}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-gray-500">Colour</span>
                        <span className={`font-semibold ${color ? 'text-gray-800' : 'text-gray-300'}`}>
                          {color ? (
                            <span className="flex items-center gap-1.5">
                              <span className="w-3 h-3 rounded-full border border-gray-200" style={{ background: color.hex }} />
                              {color.name}
                            </span>
                          ) : '—'}
                        </span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-gray-500">Size</span>
                        <span className={`font-semibold ${size ? 'text-gray-800' : 'text-gray-300'}`}>{size || '—'}</span>
                      </div>
                    </div>
                  </div>

                  {/* Notes */}
                  <div>
                    <h3 className="font-bold text-gray-900 mb-2">
                      Special Notes
                      <span className="text-gray-400 font-normal text-sm ml-1">(optional)</span>
                    </h3>
                    <textarea
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      rows={4}
                      placeholder={`Tell ${artisanName} about specific patterns, measurements, inscriptions, deadline or any special requirements…`}
                      className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:border-violet-400 outline-none resize-none text-sm transition-colors"
                    />
                    <p className="text-xs text-gray-400 mt-1">{notes.length}/300 characters</p>
                  </div>

                  {/* Artisan info */}
                  <div className="flex items-center gap-3 bg-gray-50 rounded-xl p-3">
                    <div className="w-10 h-10 rounded-full overflow-hidden bg-gray-200 flex-shrink-0">
                      <img
                        src={product.artisan?.avatar?.url || `https://ui-avatars.com/api/?name=${artisanName}&background=8B4513&color=fff&size=40`}
                        alt={artisanName} className="w-full h-full object-cover"
                      />
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-gray-900">{artisanName}</p>
                      <p className="text-xs text-gray-500">Will be notified instantly via popup</p>
                    </div>
                  </div>
                </motion.div>
              )}

            </AnimatePresence>
          </div>

          {/* ── Footer navigation ─────────────────────────────────── */}
          <div className="px-6 py-4 border-t border-gray-100 flex gap-3 flex-shrink-0 bg-white">
            {step > 1 ? (
              <button onClick={() => setStep(s => s - 1)}
                className="flex-1 py-3 border-2 border-gray-200 rounded-xl font-semibold text-gray-600 hover:bg-gray-50 transition-colors">
                ← Back
              </button>
            ) : (
              <button onClick={onClose}
                className="flex-1 py-3 border-2 border-gray-200 rounded-xl font-semibold text-gray-600 hover:bg-gray-50 transition-colors">
                Cancel
              </button>
            )}

            {step < 3 ? (
              <motion.button
                whileTap={{ scale: 0.97 }}
                onClick={() => setStep(s => s + 1)}
                className="flex-1 py-3 bg-gradient-to-r from-violet-600 to-purple-600 text-white rounded-xl font-semibold hover:shadow-lg transition-all"
              >
                Next →
              </motion.button>
            ) : (
              <motion.button
                whileTap={{ scale: 0.97 }}
                onClick={handleSend}
                disabled={status !== 'idle' || !hasAny || isOwnProduct || !canSendRequest}
                className={`flex-1 py-3 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all ${status === 'sent'
                  ? 'bg-green-500 text-white'
                  : 'bg-gradient-to-r from-violet-600 to-purple-600 text-white hover:shadow-lg disabled:opacity-50'
                  }`}
              >
                {status === 'sent' ? (
                  <><FiCheck className="h-4 w-4" /> Sent!</>
                ) : status === 'sending' ? (
                  <><FiLoader className="h-4 w-4 animate-spin" /> Sending…</>
                ) : (
                  <><FiSend className="h-4 w-4" /> Send Request</>
                )}
              </motion.button>
            )}
          </div>

        </motion.div>
      </motion.div>
    </AnimatePresence>
  );
};

export default ProductCustomizationModal;

import api from '../services/api';
// In your profile component, add this function
const handleAvatarUpload = async (e) => {
  const file = e.target.files[0];
  if (!file) return;

  const formData = new FormData();
  formData.append('avatar', file);

  try {
    const response = await api.post('/users/avatar', formData, {
      headers: { 'Content-Type': 'multipart/form-data' }
    });

    if (response.data.success) {
      updateUser({ ...user, avatar: response.data.avatar });
      toast.success('Profile picture updated!');
    }
  } catch (error) {
    toast.error('Failed to upload image');
  }
};

// In your JSX:
<input
  type="file"
  accept="image/*"
  onChange={handleAvatarUpload}
  className="hidden"
  ref={fileInputRef}
/>

// src/components/SecureChatList.js
import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FiMessageCircle, FiClock, FiCheck, FiCheckCircle,
  FiLock, FiShoppingBag, FiPackage
} from 'react-icons/fi';
import { useSecureChat } from '../context/SecureChatContext';
import { useAuth } from '../context/AuthContext';

const SecureChatList = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { rooms, loadRooms, joinRoom, unreadCount } = useSecureChat();

  useEffect(() => {
    loadRooms();
  }, []);

  const handleOpenChat = async (room) => {
    const success = await joinRoom(room._id);
    if (success) {
      navigate(`/chat/${room._id}`);
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'accepted':
        return <FiCheckCircle className="text-green-500" />;
      case 'quote_sent':
        return <FiClock className="text-orange-500" />;
      case 'in_progress':
        return <FiMessageCircle className="text-primary" />;
      default:
        return <FiLock className="text-gray-400" />;
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-lg overflow-hidden">
      <div className="p-4 border-b bg-gradient-to-r from-primary/5 to-transparent">
        <h3 className="font-semibold text-gray-900 flex items-center">
          <FiMessageCircle className="mr-2 text-primary" />
          Customization Chats
          {unreadCount > 0 && (
            <span className="ml-2 px-2 py-1 bg-red-500 text-white text-xs rounded-full">
              {unreadCount} new
            </span>
          )}
        </h3>
      </div>

      <div className="divide-y divide-gray-100 max-h-96 overflow-y-auto">
        {rooms.length === 0 ? (
          <div className="p-8 text-center">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <FiMessageCircle className="h-8 w-8 text-gray-400" />
            </div>
            <p className="text-gray-500">No active customization chats</p>
            <p className="text-sm text-gray-400 mt-2">
              Start customizing a product to begin chatting
            </p>
          </div>
        ) : (
          rooms.map((room) => (
            <motion.div
              key={room._id}
              whileHover={{ x: 4 }}
              onClick={() => handleOpenChat(room)}
              className="p-4 hover:bg-gray-50 cursor-pointer transition-colors"
            >
              <div className="flex items-start space-x-3">
                {/* Product Image */}
                <div className="relative">
                  <img
                    src={room.product?.image || 'https://via.placeholder.com/50'}
                    alt={room.product?.name}
                    className="w-16 h-16 rounded-lg object-cover"
                  />
                  {room.unreadCount?.[user?._id] > 0 && (
                    <span className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white text-xs rounded-full flex items-center justify-center">
                      {room.unreadCount[user._id]}
                    </span>
                  )}
                </div>

                {/* Chat Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <h4 className="font-medium text-gray-900 truncate">
                      {room.product?.name}
                    </h4>
                    <span className="text-xs text-gray-500">
                      {new Date(room.lastMessage?.timestamp).toLocaleDateString()}
                    </span>
                  </div>

                  <p className="text-sm text-gray-600 mb-2 line-clamp-1">
                    {room.lastMessage?.message}
                  </p>

                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-2">
                      <img
                        src={room.participants?.find(p => p._id !== user?._id)?.avatar || 'https://via.placeholder.com/24'}
                        alt="artisan"
                        className="w-6 h-6 rounded-full"
                      />
                      <span className="text-xs text-gray-500">
                        {room.participants?.find(p => p._id !== user?._id)?.name}
                      </span>
                    </div>

                    <div className="flex items-center space-x-2">
                      <span className="text-xs text-gray-400 flex items-center">
                        <FiLock className="mr-1 h-3 w-3" />
                        Private
                      </span>
                      <span className={`text-sm ${
                        room.customization?.status === 'accepted' ? 'text-green-600' :
                        room.customization?.status === 'quote_sent' ? 'text-orange-600' :
                        'text-primary'
                      }`}>
                        {getStatusIcon(room.customization?.status)}
                      </span>
                    </div>
                  </div>
                </div>
              </div>

              {/* Customization Summary */}
              {room.customization && (
                <div className="mt-3 pt-3 border-t border-gray-100">
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-gray-600">
                      Options: {Object.keys(room.customization.options || {}).length}
                    </span>
                    <span className="font-medium text-primary">
                      Rs{room.customization.price}
                    </span>
                  </div>
                </div>
              )}
            </motion.div>
          ))
        )}
      </div>
    </div>
  );
};

export default SecureChatList;

// src/components/SecureCustomizationChat.js
import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  FiSend, FiPaperclip, FiImage, FiX, FiCheck,
  FiClock, FiShoppingCart, FiUser, FiStar,
  FiDownload, FiEye, FiTrash2, FiMessageCircle,
  FiLock, FiShield, FiCheckCircle, FiAlertCircle
} from 'react-icons/fi';
import { useSecureChat } from '../context/SecureChatContext';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';
import api from '../services/api';
import toast from 'react-hot-toast';

const SecureCustomizationChat = ({
  isOpen,
  onClose,
  product,
  artisan,
  initialCustomization = null
}) => {
  const { user } = useAuth();
  const {
    joinRoom,
    leaveRoom,
    sendMessage,
    messages,
    activeRoom,
    sendTyping,
    createCustomizationRoom,
    updateCustomization,
    loading
  } = useSecureChat();

  const { addToCart } = useCart();

  const [chatMessage, setChatMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [typingTimeout, setTypingTimeout] = useState(null);
  const [attachments, setAttachments] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [customizationData, setCustomizationData] = useState(initialCustomization || {
    options: {},
    dimensions: { width: '', height: '', depth: '' },
    notes: '',
    quantity: 1,
    deadline: '',
    status: 'draft',
    price: product?.price || 0
  });
  const [showQuote, setShowQuote] = useState(false);
  const [quoteAccepted, setQuoteAccepted] = useState(false);
  const [roomInitialized, setRoomInitialized] = useState(false);

  const chatEndRef = useRef(null);
  const fileInputRef = useRef(null);
  const typingTimeoutRef = useRef(null);

  // Initialize secure chat room
  useEffect(() => {
    if (isOpen && user && product && !roomInitialized) {
      initializeChat();
    }

    return () => {
      if (activeRoom) {
        leaveRoom();
      }
    };
  }, [isOpen, user, product]);

  // Scroll to bottom when new messages arrive
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, activeRoom]);

  // Handle typing indicator
  useEffect(() => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }

    if (chatMessage) {
      sendTyping(true);
      typingTimeoutRef.current = setTimeout(() => {
        sendTyping(false);
      }, 1000);
    } else {
      sendTyping(false);
    }

    return () => {
      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }
    };
  }, [chatMessage, sendTyping]);

  const initializeChat = async () => {
    try {
      const room = await createCustomizationRoom(
        artisan?._id || product?.artisan?._id,
        product?._id,
        customizationData
      );

      if (room) {
        await joinRoom(room._id);
        setRoomInitialized(true);
      }
    } catch (error) {
      console.error('Failed to initialize chat:', error);
      toast.error('Could not start customization chat');
    }
  };

  const handleSendMessage = async () => {
    if (!chatMessage.trim() && attachments.length === 0) return;

    let messageText = chatMessage;

    // Add attachments to message
    if (attachments.length > 0) {
      const attachmentUrls = attachments.map(a => a.url).join('\n');
      messageText = `${chatMessage}\n\n📎 Attachments:\n${attachmentUrls}`;

      // Clear attachments after sending
      setAttachments([]);
    }

    const success = await sendMessage(messageText, customizationData._id);

    if (success) {
      setChatMessage('');
    }
  };

  const handleFileUpload = async (e) => {
    const files = Array.from(e.target.files);
    if (files.length === 0) return;

    setUploading(true);

    try {
      const uploadPromises = files.map(async (file) => {
        const formData = new FormData();
        formData.append('file', file);
        formData.append('type', 'chat_attachment');

        const response = await api.post('/users/upload/chat', formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });

        return {
          url: response.data.url,
          name: file.name,
          type: file.type,
          size: file.size
        };
      });

      const uploadedFiles = await Promise.all(uploadPromises);
      setAttachments(prev => [...prev, ...uploadedFiles]);

      toast.success(`${uploadedFiles.length} file(s) uploaded`);
    } catch (error) {
      toast.error('Failed to upload files');
    } finally {
      setUploading(false);
    }
  };

  const removeAttachment = (index) => {
    setAttachments(prev => prev.filter((_, i) => i !== index));
  };

  const handleQuoteAction = async (accept) => {
    if (accept) {
      setQuoteAccepted(true);
      await updateCustomization(customizationData._id, {
        status: 'accepted',
        acceptedAt: new Date().toISOString()
      });

      await sendMessage(
        `✅ I accept the quote of Rs${customizationData.price}. Please proceed with the customization.`,
        customizationData._id
      );

      toast.success('Quote accepted!');
    } else {
      await sendMessage(
        `❌ I'd like to negotiate the price. Can we discuss further?`,
        customizationData._id
      );

      toast.success('Quote declined - you can continue negotiating');
    }

    setShowQuote(false);
  };

  const handleAddToCart = () => {
    const cartItem = {
      ...product,
      customization: customizationData,
      quantity: customizationData.quantity,
      finalPrice: customizationData.price
    };

    addToCart(cartItem);
    toast.success('Custom item added to cart!');
    onClose();
  };

  const currentRoomMessages = activeRoom ? messages[activeRoom] || [] : [];

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 overflow-hidden">
        {/* Secure Overlay */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="absolute inset-0 bg-black/50 backdrop-blur-sm"
          onClick={onClose}
        />

        {/* Chat Modal */}
        <motion.div
          initial={{ x: '100%' }}
          animate={{ x: 0 }}
          exit={{ x: '100%' }}
          transition={{ type: 'tween', duration: 0.3 }}
          className="absolute right-0 top-0 bottom-0 w-full max-w-2xl bg-white shadow-2xl flex flex-col"
        >
          {/* Header with Security Badge */}
          <div className="bg-gradient-to-r from-primary to-primary-dark text-white p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <div className="flex items-center space-x-2 bg-white/20 px-3 py-1 rounded-full">
                  <FiLock className="h-3 w-3" />
                  <span className="text-xs font-medium">End-to-End Encrypted</span>
                </div>
                <div className="flex items-center space-x-1 bg-green-500/20 px-3 py-1 rounded-full">
                  <FiShield className="h-3 w-3" />
                  <span className="text-xs font-medium">Private Chat</span>
                </div>
              </div>
              <button
                onClick={onClose}
                className="p-2 hover:bg-white/20 rounded-lg transition-colors"
              >
                <FiX className="h-5 w-5" />
              </button>
            </div>

            <div className="flex items-center space-x-4 mt-4">
              <div className="relative">
                <img
                  src={artisan?.avatar?.url || product?.artisan?.avatar?.url || 'https://via.placeholder.com/50'}
                  alt={artisan?.name || product?.artisan?.name}
                  className="w-16 h-16 rounded-full object-cover border-2 border-white"
                />
                <div className="absolute bottom-0 right-0 w-4 h-4 bg-green-500 border-2 border-white rounded-full"></div>
              </div>
              <div className="flex-1">
                <h3 className="font-bold text-lg">
                  {artisan?.name || product?.artisan?.name}
                </h3>
                <p className="text-sm opacity-90 flex items-center">
                  <FiStar className="h-4 w-4 fill-current mr-1" />
                  {artisan?.rating || product?.artisan?.rating || 4.8} · Artisan
                </p>
