// src/context/AuthContext.js
import React, { createContext, useState, useContext, useEffect } from 'react';
import api from '../services/api';
import toast from 'react-hot-toast';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [token, setToken] = useState(localStorage.getItem('token'));

  useEffect(() => {
    const initAuth = async () => {
      try {
        const storedToken = localStorage.getItem('token');
        const storedUser = localStorage.getItem('user');

        if (storedToken && storedUser) {
          const parsedUser = JSON.parse(storedUser);

          // Verify token is still valid
          api.defaults.headers.common['Authorization'] = `Bearer ${storedToken}`;

          // Optional: Verify token with backend
          try {
            const response = await api.get('/auth/me');
            if (response.data.success) {
              setUser(response.data.user);
              setToken(storedToken);
            } else {
              // Token invalid, clear storage
              localStorage.removeItem('token');
              localStorage.removeItem('user');
              delete api.defaults.headers.common['Authorization'];
            }
          } catch (error) {
            console.error('Token verification failed:', error);
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            delete api.defaults.headers.common['Authorization'];
            setUser(null);
            setToken(null);
          }
        }
      } catch (e) {
        console.error('Failed to restore auth state:', e);
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        delete api.defaults.headers.common['Authorization'];
      } finally {
        setLoading(false);
      }
    };

    initAuth();
  }, []);

  const login = async (email, password) => {
    try {
      console.log('Attempting login for:', email);

      const res = await api.post('/auth/login', { email, password });
      console.log('Login response:', res.data);

      const { token, user } = res.data;

      if (!token || !user) {
        throw new Error('Invalid response from server');
      }

      localStorage.setItem('token', token);
      localStorage.setItem('user', JSON.stringify(user));

      api.defaults.headers.common['Authorization'] = `Bearer ${token}`;

      setUser(user);
      setToken(token);

      toast.success(`Welcome back, ${user.name}!`);
      return { success: true, user };

    } catch (err) {
      console.error('Login error:', err);
      let message = 'Login failed';

      if (err.message === 'Network Error' || err.message?.includes('connect')) {
        message = 'Cannot connect to server. Please make sure the backend is running (check REACT_APP_API_URL in .env).';
      } else if (err.response?.data?.message) {
        message = err.response.data.message;
      } else if (err.message) {
        message = err.message;
      }

      toast.error(message);
      return { success: false, error: message, locked: err.response?.data?.locked || false, lockedUntil: err.response?.data?.lockedUntil || null };
    }
  };

  const register = async (userData) => {
    try {
      console.log('Register attempt with data:', userData);

      const res = await api.post('/auth/register', userData);
      console.log('Register response:', res.data);

      toast.success('Registration successful! Welcome to Madio Craft.');
      return { success: true };

    } catch (err) {
      console.error('Registration error:', err);
      let message = 'Registration failed';

      if (err.message === 'Network Error' || err.message?.includes('connect')) {
        message = 'Cannot connect to server. Please make sure the backend is running (check REACT_APP_API_URL in .env).';
      } else if (err.response?.data?.message) {
        message = err.response.data.message;
      } else if (err.message) {
        message = err.message;
      }

      toast.error(message);
      return { success: false, error: message };
    }
  };

  const logout = (silent = false) => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');

    delete api.defaults.headers.common['Authorization'];

    setUser(null);
    setToken(null);

    if (!silent) {
      toast.success('Logged out successfully');
    }
  };

  const updateUser = (updatedUser) => {
    setUser(updatedUser);
    localStorage.setItem('user', JSON.stringify(updatedUser));
  };

  const value = {
    user,
    loading,
    token,
    login,
    register,
    logout,
    updateUser,
    isAuthenticated: !!user && !!token,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

import React, { createContext, useState, useContext, useEffect, useCallback } from 'react';
import api from '../services/api';
import { useAuth } from './AuthContext';
import { useSocket } from './SocketContext';

const ChatContext = createContext();

export const useChat = () => useContext(ChatContext);

export const ChatProvider = ({ children }) => {
  const [activeRoom, setActiveRoom] = useState(null);
  const [rooms, setRooms] = useState([]);
  const [messages, setMessages] = useState({});
  const [unreadCount, setUnreadCount] = useState(0);
  const { user } = useAuth();
  // Reuse the shared socket from SocketContext — no duplicate connections
  const { socket } = useSocket();

  useEffect(() => {
    if (!socket) return;

    const handleReceiveMessage = ({ roomId, message, sender, timestamp }) => {
      setMessages(prev => ({
        ...prev,
        [roomId]: [...(prev[roomId] || []), { message, sender, timestamp }]
      }));
    };

    socket.on('receive-message', handleReceiveMessage);
    return () => { socket.off('receive-message', handleReceiveMessage); };
  }, [socket]);

  const joinRoom = useCallback((roomId) => {
    if (socket && roomId) {
      socket.emit('join-room', roomId);
      setActiveRoom(roomId);
      loadMessages(roomId);
    }
  }, [socket]);

  const leaveRoom = useCallback(() => {
    if (activeRoom && socket) {
      socket.emit('leave-room', activeRoom);
    }
    setActiveRoom(null);
  }, [activeRoom, socket]);

  const sendMessage = useCallback((message, roomId = activeRoom) => {
    if (socket && roomId) {
      socket.emit('send-message', { roomId, message, sender: user?._id });
    }
  }, [socket, activeRoom, user]);

  const loadRooms = useCallback(async () => {
    try {
      const res = await api.get('/chat/rooms');
      setRooms(res.data.rooms || []);
      const totalUnread = (res.data.rooms || []).reduce((sum, room) => {
        return sum + (room.unreadCount?.[user?._id] || 0);
      }, 0);
      setUnreadCount(totalUnread);
    } catch (err) {
      console.error('Failed to load chat rooms:', err);
    }
  }, [user]);

  const loadMessages = useCallback(async (roomId) => {
    try {
      const res = await api.get(`/chat/rooms/${roomId}/messages`);
      setMessages(prev => ({ ...prev, [roomId]: res.data.messages || [] }));
    } catch (err) {
      console.error('Failed to load messages:', err);
    }
  }, []);

  const createRoom = useCallback(async (artisanId, productId) => {
    try {
      const res = await api.post('/chat/room', { artisanId, productId });
      setRooms(prev => [res.data.room, ...prev]);
      return res.data.room;
    } catch (err) {
      console.error('Failed to create room:', err);
      return null;
    }
  }, []);

  const value = {
    socket, activeRoom, rooms,
    messages: messages[activeRoom] || [],
    unreadCount, joinRoom, leaveRoom,
    sendMessage, loadRooms, loadMessages, createRoom,
    allMessages: messages
  };

  return (
    <ChatContext.Provider value={value}>
      {children}
    </ChatContext.Provider>
  );
};

// src/context/SecureChatContext.js
import React, { createContext, useState, useContext, useEffect, useCallback } from 'react';
import api from '../services/api';
import { useAuth } from './AuthContext';
import { useSocket } from './SocketContext';
import toast from 'react-hot-toast';

const SecureChatContext = createContext();

export const useSecureChat = () => {
  const context = useContext(SecureChatContext);
  if (!context) throw new Error('useSecureChat must be used within a SecureChatProvider');
  return context;
};

export const SecureChatProvider = ({ children }) => {
  const [activeRoom, setActiveRoom] = useState(null);
  const [rooms, setRooms] = useState([]);
  const [messages, setMessages] = useState({});
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(false);

  const { user, isAuthenticated } = useAuth();
  // Reuse the shared socket from SocketContext — no duplicate connections
  const { socket } = useSocket();
  const connected = !!socket?.connected;

  useEffect(() => {
    if (!socket) return;

    const handleReceiveMessage = (data) => {
      const { roomId, message, sender, timestamp, customizationId, _id } = data;
      setMessages(prev => {
        const roomMessages = prev[roomId] || [];
        if (roomMessages.some(m => m._id === _id)) return prev;
        return {
          ...prev,
          [roomId]: [...roomMessages, {
            _id, message, sender, timestamp, customizationId,
            isOwn: sender === (user?._id || user?.id)
          }]
        };
      });

      if (sender !== (user?._id || user?.id)) {
        setUnreadCount(prev => prev + 1);
        toast.custom((t) => (
          <div onClick={() => window.location.href = `/chat/${roomId}`}
            className="bg-white rounded-lg shadow-lg p-4 cursor-pointer hover:bg-gray-50 border-l-4 border-primary">
            <p className="font-semibold text-sm">New message</p>
            <p className="text-xs text-gray-600 mt-1">{message.substring(0, 50)}...</p>
          </div>
        ), { duration: 3000 });
      }
    };

    const handleTyping = ({ roomId, isTyping, userId }) => {
      console.log(`User ${userId} is ${isTyping ? 'typing' : 'not typing'} in room ${roomId}`);
    };

    socket.on('receive-message', handleReceiveMessage);
    socket.on('user-typing', handleTyping);

    return () => {
      socket.off('receive-message', handleReceiveMessage);
      socket.off('user-typing', handleTyping);
    };
  }, [socket, user]);

  const joinRoom = useCallback(async (roomId) => {
    if (!socket || !roomId) return false;
    try {
      socket.emit('join-room', roomId);
      setActiveRoom(roomId);
      setLoading(true);
      const response = await api.get(`/chat/rooms/${roomId}/messages`);
      if (response.data.success) {
        const loadedMessages = (response.data.messages || []).map(msg => ({
          ...msg, isOwn: msg.sender === (user?._id || user?.id)
        }));
        setMessages(prev => ({ ...prev, [roomId]: loadedMessages }));
      }
      return true;
    } catch (error) {
      console.error('Failed to join room:', error);
      toast.error('Failed to load chat messages');
      return false;
    } finally {
      setLoading(false);
    }
  }, [socket, user]);

  const leaveRoom = useCallback(() => {
    if (activeRoom && socket) { socket.emit('leave-room', activeRoom); setActiveRoom(null); }
  }, [activeRoom, socket]);

  const sendMessage = useCallback(async (message, customizationId = null) => {
    if (!socket || !activeRoom || !message.trim()) return false;
    try {
      const response = await api.post('/chat/messages', {
        roomId: activeRoom, message: message.trim(), customizationId, type: 'text'
      });
      return response.data.success || false;
    } catch (error) {
      console.error('Failed to send message:', error);
      toast.error('Failed to send message');
      return false;
    }
  }, [socket, activeRoom]);

  const sendTyping = useCallback((isTyping) => {
    if (socket && activeRoom) socket.emit('typing', { roomId: activeRoom, isTyping });
  }, [socket, activeRoom]);

  const createCustomizationRoom = useCallback(async (artisanId, productId, customizationData = {}) => {
    try {
      setLoading(true);
      const response = await api.post('/chat/customization/room', { artisanId, productId, customizationData });
      if (response.data.success) {
        const room = response.data.room;
        setRooms(prev => prev.some(r => r._id === room._id) ? prev : [room, ...prev]);
        return room;
      }
      return null;
    } catch (error) {
      console.error('Failed to create room:', error);
      toast.error(error.response?.data?.message || 'Failed to start chat');
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  const updateCustomization = useCallback(async (roomId, updates) => {
    try {
      const response = await api.put(`/chat/customization/${roomId}`, updates);
      return response.data.success;
    } catch (error) {
      console.error('Failed to update customization:', error);
      toast.error('Failed to update customization');
      return false;
    }
  }, []);

  const loadRooms = useCallback(async () => {
    try {
      setLoading(true);
      const response = await api.get('/chat/rooms');
      if (response.data.success) {
        setRooms(response.data.rooms || []);
        const totalUnread = (response.data.rooms || []).reduce(
          (sum, room) => sum + (room.unreadCount?.[user?._id] || 0), 0
        );
        setUnreadCount(totalUnread);
      }
    } catch (error) {
      console.error('Failed to load rooms:', error);
    } finally {
      setLoading(false);
    }
  }, [user]);

  const value = {
    socket, activeRoom, rooms, messages, unreadCount, loading, connected,
    joinRoom, leaveRoom, sendMessage, sendTyping, createCustomizationRoom,
    updateCustomization, loadRooms,
  };

  return (
    <SecureChatContext.Provider value={value}>
      {children}
    </SecureChatContext.Provider>
  );
};

// context/SocketContext.js
import React, { createContext, useContext, useEffect, useRef, useState } from 'react';
import { io } from 'socket.io-client';
import { useAuth } from './AuthContext';

const SocketContext = createContext();

export const useSocket = () => {
  const context = useContext(SocketContext);
  if (!context) throw new Error('useSocket must be used within a SocketProvider');
  return context;
};

export const SocketProvider = ({ children }) => {
  const [socket, setSocket] = useState(null);
  const { user, isAuthenticated, loading } = useAuth();
  const socketRef = useRef(null);

  useEffect(() => {
    // Wait for auth to finish initialising, and only connect when we have a real user id
    if (loading) return;
    if (!isAuthenticated || !user?._id) {
      // Disconnect any existing socket when user logs out
      if (socketRef.current) {
        socketRef.current.disconnect();
        socketRef.current = null;
        setSocket(null);
      }
      return;
    }

    // Avoid reconnecting when the same user is already connected
    if (socketRef.current?.connected) return;

    const socketUrl =
      process.env.REACT_APP_SOCKET_URL ||
      process.env.REACT_APP_API_URL?.replace('/api', '') ||
      'http://localhost:5000';

    const newSocket = io(socketUrl, {
      auth: { token: localStorage.getItem('token') },
      transports: ['websocket'],
      reconnection: true,
      reconnectionDelay: 1000,
    });

    newSocket.on('connect', () => {
      // user.id is the correct field (auth returns {id: user._id, ...})
      const userId = user.id || user._id;
      console.log(`Socket connected as user ${userId}`);
      newSocket.emit('register-user', userId);
      // Also emit join-user for legacy compatibility
      newSocket.emit('join-user', userId);
    });

    newSocket.on('connect_error', (err) => {
      console.warn('Socket connection error:', err.message);
    });

    newSocket.on('disconnect', (reason) => {
      console.log('Socket disconnected:', reason);
    });

    socketRef.current = newSocket;
    setSocket(newSocket);

    return () => {
      newSocket.disconnect();
      socketRef.current = null;
    };
  }, [isAuthenticated, user?._id, loading]);

  return (
    <SocketContext.Provider value={{ socket }}>
      {children}
    </SocketContext.Provider>
  );
};

