            {/* RIGHT — INFO CARD */}
            <div>
              <div className="bg-gray-100 rounded-2xl p-6 space-y-4">

                <h3 className="font-bold">Artisan Info</h3>

                <div className="flex items-center gap-2 text-sm">
                  <FiMapPin /> {artisan.location}
